    /// <summary>Looks up an exact property spelling ("Script=Latin",
    /// "gc=Lu", "Alphabetic", ...). Returns false for unknown names.</summary>
    public static bool TryGetRanges(string name, out int[] pairs, out int start, out int count)
    {
        if (!_index.TryGetValue(name, out var entry))
        {
            pairs = System.Array.Empty<int>();
            start = 0;
            count = 0;
            return false;
        }

        pairs = _pairs ??= Decode();
        start = entry.Start;
        count = entry.Count;
        return true;
    }

    private static int[] Decode()
    {
        var bytes = System.Convert.FromBase64String(Blob);
        var pairs = new int[PairCount * 2];
        var bi = 0;
        for (var i = 0; i < PairCount; i++)
        {
            var lo = ReadVarint(bytes, ref bi);
            var len = ReadVarint(bytes, ref bi);
            pairs[i * 2] = lo;
            pairs[i * 2 + 1] = lo + len;
        }

        return pairs;
    }

    private static int ReadVarint(byte[] bytes, ref int i)
    {
        var value = 0;
        var shift = 0;
        while (true)
        {
            var b = bytes[i++];
            value |= (b & 0x7F) << shift;
            if ((b & 0x80) == 0)
            {
                return value;
            }

            shift += 7;
        }
    }
